/**
 * Ergonomic re-exports of the (auto-generated) OpenAPI types.
 *
 * `src/types/openapi.d.ts` is regenerated by `npm run sync` and exposes
 * everything via the heavyweight `paths`/`components` interfaces. The
 * aliases here narrow them down to the shapes consumers actually
 * import — request bodies, response bodies, common enums.
 *
 * If you need a type that isn't aliased yet, you can always reach the
 * raw OpenAPI types via `import type { components, paths } from
 * '@apiframe-ai/sdk'`.
 */

import type { components, paths } from './openapi.js';

