// ---------------------------------------------------------------------------
// Job query / list params (derived from path-level operation types)
// ---------------------------------------------------------------------------

/** Query parameters accepted by `GET /v2/jobs`. */
export type JobsListQuery = NonNullable<paths['/v2/jobs']['get']['parameters']['query']>;

/** Query parameters accepted by `GET /v2/loras`. */
